2393:   // We allow posting restyles from within change hint handling, but not from
2394:   // within the restyle algorithm itself.
2395:   MOZ_ASSERT(!ServoStyleSet::IsInServoTraversal());
2396: 
2397:   if (!aRestyleHint && !aMinChangeHint) {
2398:     // FIXME(emilio): we should assert against this instead.
