6421: void PresShell::PaintAndRequestComposite(nsIFrame* aFrame,
6422:                                          WindowRenderer* aRenderer,
6423:                                          PaintFlags aFlags) {
6424:   if (!mIsActive) {
6425:     return;
6426:   }
6427: 
6428:   NS_ASSERTION(aRenderer, "Must be in paint event");
6429:   if (aRenderer->AsFallback()) {
6430:     // The fallback renderer doesn't do any retaining, so we just need to
6431:     // notify the view and widget that we're invalid, and we'll do a
6432:     // paint+composite from the PaintWindow callback.
6433:     if (nsIWidget* widget = aFrame ? aFrame->GetOwnWidget() : nullptr) {
6434:       auto bounds = widget->GetBounds();
6435:       widget->Invalidate(LayoutDeviceIntRect({}, bounds.Size()));
6436:     }
6437:     return;
6438:   }
6439: 
6440:   // Otherwise we're a retained WebRenderLayerManager, so we want to call
6441:   // Paint to update with any changes and push those to WR.
6442:   PaintInternalFlags flags = PaintInternalFlags::None;
6443:   if (aFlags & PaintFlags::PaintSyncDecodeImages) {
6444:     flags |= PaintInternalFlags::PaintSyncDecodeImages;
6445:   }
6446:   if (aFlags & PaintFlags::PaintCompositeOffscreen) {
6447:     flags |= PaintInternalFlags::PaintCompositeOffscreen;
6448:   }
6449:   PaintInternal(aFrame, aRenderer, flags);
6450: }
